INSERT INTO TADMIN_MST_ROXMEGT (
	 ROKEY
	 ,MEKEY
	 ,EQTYPE
	 ,INSERTURKEY
	 ,INSERTDATE
	 ,UPDATEURKEY
	 ,UPDATEDATE
) VALUES ( 
	 #{rokey}
	 ,#{mekey}
	 ,#{eqtype}
	 ,#{surkey}
	 ,#{sysdate}
	 ,#{surkey}
	 ,#{sysdate}
)

