DELETE 
  FROM TADMIN_MST_ROXMEGT



			ROKEY = #{rokey}
   			AND MEKEY IN (SELECT MEKEY FROM TADMIN_MST_ME WHERE APKEY = #{apkey})


			ROKEY = #{rokey}
			AND MEKEY = #{mekey}
